const updateCoupon = `-- name: UpdateCoupon :execrows
UPDATE coupons
SET code_display = $2,
    normalized_code = $3,
    code_hash = $4,
    discount_kind = $5,
    discount_value = $6,
    min_merchandise_idr = $7,
    max_total_uses = $8,
    max_per_customer_uses = $9,
    starts_at = $10,
    ends_at = $11,
    state = $12,
    scope = $13,
    version = $14,
    policy_version = $15,
    updated_at = $16
WHERE id = $1 AND store_id = $17 AND version = $18
`

type UpdateCouponParams struct {
	ID                 string             `json:"id"`
	CodeDisplay        string             `json:"code_display"`
	NormalizedCode     string             `json:"normalized_code"`
	CodeHash           string             `json:"code_hash"`
	DiscountKind       string             `json:"discount_kind"`
	DiscountValue      int64              `json:"discount_value"`
	MinMerchandiseIdr  int64              `json:"min_merchandise_idr"`
	MaxTotalUses       *int64             `json:"max_total_uses"`
	MaxPerCustomerUses *int64             `json:"max_per_customer_uses"`
	StartsAt           pgtype.Timestamptz `json:"starts_at"`
	EndsAt             pgtype.Timestamptz `json:"ends_at"`
	State              string             `json:"state"`
	Scope              string             `json:"scope"`
	Version            int32              `json:"version"`
	PolicyVersion      int32              `json:"policy_version"`
	UpdatedAt          time.Time          `json:"updated_at"`
	StoreID            string             `json:"store_id"`
	Version_2          int32              `json:"version_2"`
}

func (q *Queries) UpdateCoupon(ctx context.Context, arg UpdateCouponParams) (int64, error) {
	result, err := q.db.Exec(ctx, updateCoupon,
		arg.ID,
		arg.CodeDisplay,
		arg.NormalizedCode,
		arg.CodeHash,
		arg.DiscountKind,
		arg.DiscountValue,
		arg.MinMerchandiseIdr,
		arg.MaxTotalUses,
		arg.MaxPerCustomerUses,
		arg.StartsAt,
		arg.EndsAt,
		arg.State,
		arg.Scope,
		arg.Version,
		arg.PolicyVersion,
		arg.UpdatedAt,
		arg.StoreID,
		arg.Version_2,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

const updateCouponReservationState = `-- name: UpdateCouponReservationState :execrows
UPDATE coupon_reservations
SET state = $2,
    consumed_at = CASE WHEN $2 = 'CONSUMED' THEN $3 ELSE consumed_at END,
    released_at = CASE WHEN $2 = 'RELEASED' THEN $3 ELSE released_at END,
    updated_at = $3
WHERE id = $1 AND state = $4
`

type UpdateCouponReservationStateParams struct {
	ID        string    `json:"id"`
	State     string    `json:"state"`
	UpdatedAt time.Time `json:"updated_at"`
	State_2   string    `json:"state_2"`
}

func (q *Queries) UpdateCouponReservationState(ctx context.Context, arg UpdateCouponReservationStateParams) (int64, error) {
	result, err := q.db.Exec(ctx, updateCouponReservationState,
		arg.ID,
		arg.State,
		arg.UpdatedAt,
		arg.State_2,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}
